var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"구마회 본부가 악마의 습격을 받았다는 연락을 받았습니다만…","JPN":"祓魔会の本部が悪魔に襲撃されたという連絡を受けましたが……","ENG":"We just received a message that the headquarters of Exorcism Council was attacked by a devil...","TWN":"我收到了驅魔會總部遭到魔鬼襲擊的消息…"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"단 한 명의 사상자도 나오지 않았다는 건 예상 밖이군요.","JPN":"死傷者が一人も出なかったのは予想外ですね。","ENG":"But it's unexpected that there was not a single casualty.","TWN":"沒有出現任何傷亡，真是出乎意料。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"그 악마가 노리는 건 저희 목숨이 아니었습니다.","JPN":"あの悪魔が狙っていたのは、私たちの命ではなかったのです。","ENG":"I believe that devil was not after our lives.","TWN":"那個魔鬼的目標似乎並不是我們的性命。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"저를 찾아와서, 마르가리타 계시에 대해서 묻더군요.","JPN":"私を訪ね、マルガリータ啓示について尋ねました。","ENG":"She came to me and asked about the Revelation of Margarita.","TWN":"它來找我，詢問了關於瑪格麗特啟示的事情。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"계시라고요?","JPN":"啓示？","ENG":"Revelation?","TWN":"啟示嗎？"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그래서… 진실로 답을 하셨나요?","JPN":"それで……答えたのですか？","ENG":"So... did you answer truthfully?","TWN":"所以…你如實回答了嗎？"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"모르겠습니다.","JPN":"わかりません。","ENG":"I do not know.","TWN":"我不知道。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"포도향을 맡았다고 생각한 순간부터… 아무것도 기억이 나질 않더군요.","JPN":"ブドウの香りがしたと思った瞬間……記憶が途絶えたのです。","ENG":"The moment I thought I smelled grapes... I cannot recall any memories.","TWN":"從聞到葡萄香氣的那一刻起…我就什麼都不記得了。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"포도향이라…","JPN":"ブドウの香り……","ENG":"Grapes...?","TWN":"葡萄香氣嗎…"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그러고보니 습격 현장에 쓰러져 있던 직원들도 그런 일관된 증언을 했었죠.","JPN":"そういえば、襲撃の現場に倒れていた職員たちも同じ証言をしていました。","ENG":"Come to think of it, the ones who were also ambushed on the scene seem to say the same thing.","TWN":"說起來，倒在襲擊現場的員工們也有類似的證詞。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"저희가 쫓던 녀석들 중에도 비슷한 특징을 가진 악마가 있습니다.","JPN":"私たちが追いかけていたやつらの中にも、似た特徴を持つ悪魔がいます。","ENG":"Among the devils we were pursuing, there was one with similar characteristics.","TWN":"我們追蹤的目標中也有類似特徵的魔鬼。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"단서를 모으고 있고, 조만간 놈의 꼬리를 잡을 수 있을 겁니다.","JPN":"手がかりを集めていますので、もうすぐやつの尻尾を掴めるはずです。","ENG":"We are currently gathering clues, and we will soon have the devil in custody.","TWN":"現在正在收集線索，很快就能抓住它的尾巴了。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"악마를 찾아내는 일은 구마회의 소관이니, 그 일은 믿고 맡기겠습니다.","JPN":"悪魔を探し出すことは祓魔会の仕事ですから、この件はお任せしましょう。","ENG":"It is the duty of the Exorcism Council to find devils, so I shall entrust you with that task.","TWN":"尋找魔鬼是驅魔會的職責，這件事就交給你們了。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"하지만, 마르가리타 계시는 현세의 악에 맞설 성인을 찾기 위한 기밀 프로젝트 중 하나.","JPN":"ですが、マルガリータ啓示は現世の悪に立ち向かう聖人を探すための機密プロジェクトの一つ。","ENG":"However, the Revelation of Margarita is one of the secret projects to find a Saint who will stand against the evils of this world.","TWN":"但是，瑪格麗特啟示是為了尋找對抗現世之惡的聖人，而進行的機密項目之一。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그 추적법이 성황청의 교의에 부합하지 않는 신비주의적 방식이기에 철저한 비밀리에 취급되고 있었을 텐데…","JPN":"その追跡方法は聖皇庁の教義に適合しない神秘主義的な方法ですので、徹底した管理のもと扱われていたはずですが……","ENG":"Its tracking method is mystical, and nonconforming to Holy Curia's doctrine, so it was kept in complete secret...","TWN":"由於不符合聖皇廳的教義，是以神秘主義的方式進行的，所以一直被嚴格保密…"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"일개 악마가 어떤 경위로 계시를 알고 있었는지 의문이 남는군요.","JPN":"一介の悪魔がどういった経緯で啓示のことを知ったのか、疑問ですね。","ENG":"So the question remains as to how a mere devil knew about it.","TWN":"一個小小的魔鬼是怎麼知道啟示的，真是令人疑惑。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"의심하고 싶진 않지만, 성황청 내부에 악마의 협력자가 있을지도 모릅니다.","JPN":"疑いたくはないのですが、聖皇庁の内部に悪魔の協力者がいるのかもしれません。","ENG":"I do not wish to raise suspicion, but there may be a devil's collaborator within Holy Curia.","TWN":"雖然不想懷疑，但聖皇廳內部可能有魔鬼的同夥。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"모든 전말은 그 악마를 붙잡은 뒤에 알 수 있겠죠.","JPN":"すべての顛末はその悪魔を捕まえれば、わかるでしょう。","ENG":"Everything will be revealed once we catch that devil.","TWN":"所有真相等抓住那個魔鬼後就能知道了。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"EMPLOYEE_NPC_GREMORY_NULL","text":{"KOREA":"점장님.","JPN":"店長。","ENG":"Gremory?","TWN":"店長。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EMPLOYEE_NPC_GREMORY_NULL","text":{"KOREA":"저… 할 말이 있어요.","JPN":"あの……話があります。","ENG":"There's... something I'd like to say.","TWN":"我…有話想說。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"으음…","JPN":"うーん……","ENG":"Mm...","TWN":"嗯…"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"나 오늘은 피곤한데. 다음에 하면 안 될까?","JPN":"アタシ、今日はちょっと疲れてるの。あとにしてくれないかしら。","ENG":"I'm a little tired today. Could we talk later?","TWN":"我今天很累。可以改天再說嗎？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"EMPLOYEE_NPC_GREMORY_NULL","text":{"KOREA":"저 오늘부로 바텐더 일 관두려고요.","JPN":"私、今日からバーテンダーの仕事やめます。","ENG":"I'm thinking of quitting my job as the bartender today.","TWN":"我想辭掉調酒師的工作。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"어머, 돈이 부족한 거야? 아니면 일이 너랑 안 맞았니?","JPN":"あら、お金が足りないの？　それとも、仕事が合わない？","ENG":"Oh. Was the pay unsatisfactory? Or do you think the job isn't right for you?","TWN":"喔？是錢不夠嗎？還是工作不適合你？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"EMPLOYEE_NPC_GREMORY_NULL","text":{"KOREA":"아뇨. 급여는 지금도 충분해요. 점장님과 함께 일하면서 보람도 느꼈고요.","JPN":"いいえ。給料には満足しています。店長と一緒に働けて、やり甲斐もありました。","ENG":"No. The pay's been more than enough. And I feel rewarded working with you.","TWN":"不，工資很夠，和店長一起工作也很有成就感。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그럼 왜 떠나려는 건데애?","JPN":"なら、どうして辞めちゃうの？","ENG":"Then why are you quitting?","TWN":"那你為什麼要離開呢？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};